// Apify'dan gelen yanıtı al
const inputItem = $input.first();
const response = inputItem ? inputItem.json : {};

// --- HATA 2 ÇÖZÜMÜ: ---
// Editörün "organicResults yok" hatasını önlemek için güvenli erişim kullanıyoruz.
// Köşeli parantez kullanımı ['organicResults'] tip hatasını bypass eder.
const items = response['organicResults'] || [];

// --- GLOBAL HAFIZA (STATIC DATA) ---
const staticData = $getWorkflowStaticData('global');

// --- HATA 1 ÇÖZÜMÜ: ---
// Formdan gelen limiti al.
// 'parseInt' kaldırdık çünkü target_count zaten bir Sayı (Number).
let limit = 50; 
try {
    const setNode = $('Set Fields1').first().json;
    if (setNode.target_count !== undefined) {
        // Gelen değer zaten sayı olduğu için doğrudan eşitliyoruz.
        // Garanti olsun diye Number() içine alabiliriz ama parseInt gerekmez.
        limit = Number(setNode.target_count);
    }
} catch(e) {
    // Hata olursa limit 50 kalsın
}

// --- SAYACI YÖNETME ---
// Eğer bu değişken hafızada yoksa (ilk tur), 0'dan başlat.
if (staticData.resultsCounter === undefined) {
    staticData.resultsCounter = 0;
}

// Şu an elimizdeki sonuç sayısı kadar sayacı artır
if (items.length > 0) {
    staticData.resultsCounter += items.length;
}

// --- DEVAM ETME KARARI ---
// Eğer hafızadaki toplam sayı (resultsCounter), limitten küçükse devam et.
const hasMoreResults = items.length > 0 && staticData.resultsCounter < limit;

// Bir sonraki başlangıç indeksi
const nextStartIndex = staticData.resultsCounter + 1;

// E-posta bulma fonksiyonu
function findEmail(text) {
  if (!text) return null;
  const emailRegex = /([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9._-]+)/gi;
  const found = text.match(emailRegex);
  return found ? found[0] : null;
}

// --- GÜVENLİK VE ÇIKIŞ ---
// Eğer hiç sonuç yoksa döngüyü kıracak sinyali gönder
if (items.length === 0) {
    staticData.resultsCounter = 0;
    return [{ 
        json: {
            startIndex: nextStartIndex,
            hasMoreResults: false
        }
    }];
}

// Eğer limit dolduysa hafızayı temizle (Workflow bitiyor)
if (!hasMoreResults) {
    staticData.resultsCounter = 0;
}

// --- VERİ İŞLEME VE ÇIKTI ---
const results = items.map(item => {
  const snippet = item.description || "";
  const email = findEmail(snippet);

  return {
    name: item.title ? item.title.split(" - ")[0] : null,
    position: item.title,
    link: item.url,
    about: snippet,
    image: null, 
    email: email,
    startIndex: nextStartIndex,
    hasMoreResults: hasMoreResults
  };
});

return results.map(r => ({ json: r }));

// Get all input items
const inputItems = $input.all();
console.log("Input items count:", inputItems.length);

// Extract pagination values with correct field names
let nextStartIndex = 1;
let hasMoreResults = false;

if (inputItems && inputItems.length > 0) {
  const firstItem = inputItems[0];

  if (firstItem.json) {
    console.log("First item JSON:", JSON.stringify(firstItem.json));

    // Look for "startIndex" instead of "index"
    if (firstItem.json.startIndex !== undefined) {
      nextStartIndex = firstItem.json.startIndex;
      console.log("Found startIndex:", nextStartIndex);
    }

    // Look for "hasMoreResults" instead of "results"
    if (firstItem.json.hasMoreResults !== undefined) {
      hasMoreResults = firstItem.json.hasMoreResults;
      console.log("Found hasMoreResults:", hasMoreResults);
    }
  }
}

// Return pagination control info
return {
  json: {
    continueLoop: hasMoreResults,
    startIndex: nextStartIndex
  }
};

