// HTTP Request'ten gelen veriyi al
const items = $input.all();

// 1. E-posta Regex'i
const emailRegex = /([a-zA-Z0-9._-]+@[a-zA-Z0-9._-]+\.[a-zA-Z0-9._-]+)/gi;

// 2. Telefon Regex'i (GÜNCELLENDİ - SIKI MOD)
// Sadece + veya rakamla başlayan, içinde parantez/tire olabilen grupları arar.
const phoneRegex = /((\+|00)\d{1,3}[-.\s]?)?\(?\d{2,4}\)?[-.\s]?\d{3}[-.\s]?\d{2,4}([-.\s]?\d{2,4})?/g;

// Öncelik verilecek e-posta kelimeleri
const priorityKeywords = ['info', 'contact', 'hello', 'sales', 'iletisim', 'destek', 'export'];

return items.map(item => {
  const htmlContent = JSON.stringify(item.json); 

  // --- E-POSTA İŞLEMLERİ (Aynı kaldı) ---
  let foundEmails = [];
  let bestEmail = null;

  if (htmlContent) {
    const emailMatches = htmlContent.match(emailRegex);
    if (emailMatches) {
      emailMatches.forEach(email => {
        const cleanEmail = email.toLowerCase();
        if (!cleanEmail.match(/\.(png|jpg|jpeg|gif|css|js|webp|svg)$/i)) {
             if (!foundEmails.includes(cleanEmail)) {
                foundEmails.push(cleanEmail);
             }
        }
      });
    }
  }

  if (foundEmails.length > 0) {
    bestEmail = foundEmails.find(email => 
      priorityKeywords.some(keyword => email.includes(keyword))
    );
    if (!bestEmail) bestEmail = foundEmails[0];
  }

  // --- TELEFON İŞLEMLERİ (ÖZELLEŞTİRİLDİ) ---
  let foundPhones = [];
  let bestPhone = null;

  if (htmlContent) {
    const phoneMatches = htmlContent.match(phoneRegex);

    if (phoneMatches) {
      phoneMatches.forEach(phone => {
        // Temizlik: Boşlukları ve gereksiz karakterleri at, sadece +, rakam kalsın
        const cleanPhone = phone.trim().replace(/[^0-9+]/g, '');

        // --- SIKI FİLTRELER ---

        // Kural 1: Uzunluk Kontrolü (Uluslararası nolar genelde 10-15 hane olur)
        if (cleanPhone.length < 10 || cleanPhone.length > 16) return;

        // Kural 2: Başlangıç Kontrolü (En Önemli Kısım)
        // Sadece '+' ile veya '00' ile veya '0' ile başlayanları al.
        // (Sıradan sayıları, tarihleri ve ürün kodlarını eler)
        const isInternational = cleanPhone.startsWith('+') || cleanPhone.startsWith('00');
        const isLocalOfficial = cleanPhone.startsWith('0'); // Örn: 0212, 0532

        if (isInternational || isLocalOfficial) {

            // Kural 3: Geçersiz tekrarları ele (Örn: 0000000000)
            if (/^(\d)\1+$/.test(cleanPhone.replace('+', ''))) return;

            // Listeye ekle (Orijinal formatı koruyarak veya clean halini)
            // Okunabilirlik için orijinal 'phone' değişkenini trim edip ekliyoruz.
            const displayPhone = phone.trim();

            if (!foundPhones.includes(displayPhone)) {
                foundPhones.push(displayPhone);
            }
        }
      });
    }
  }

  // En iyi telefonu seç
  // Varsa önce '+' ile başlayanı seç, yoksa ilk bulduğunu al.
  if (foundPhones.length > 0) {
      // + ile başlayan bir numara var mı?
      const internationalOne = foundPhones.find(p => p.includes('+'));
      bestPhone = internationalOne ? internationalOne : foundPhones[0];
  }

  return {
    json: {
      url: item.json.url || item.json.link, 
      scraped_email: bestEmail,
      all_emails_found: foundEmails,
      scraped_phone: bestPhone,   // Tercihen +90... formatı gelir
      all_phones_found: foundPhones
    }
  }
});

// Türkçe karakterleri İngilizceye çeviren fonksiyon
function sanitize(str) {
    if (!str) return "";
    const map = {
        'ğ': 'g', 'ü': 'u', 'ş': 's', 'ı': 'i', 'ö': 'o', 'ç': 'c',
        'Ğ': 'G', 'Ü': 'U', 'Ş': 'S', 'İ': 'I', 'Ö': 'O', 'Ç': 'C'
    };
    return str.replace(/[ğüşıöçĞÜŞİÖÇ]/g, (m) => map[m])
              .toLowerCase()
              .replace(/[^a-z0-9]/g, '');
}

const items = $input.all();

// Referans node verilerini al
let resultsData = [];
let scraperData = [];
try { 
    resultsData = $node["Results 1"].json; 
    if (!Array.isArray(resultsData)) resultsData = [resultsData];
} catch(e) {}
try { 
    scraperData = $node["linkedin scraper1"].json;
    if (!Array.isArray(scraperData)) scraperData = [scraperData];
} catch(e) {}

return items.map((item, index) => {
    const json = item.json; 

    // --- İSİM BULMA ---
    let fullName = "";
    if (resultsData?.[index]) fullName = resultsData[index].name;
    if (!fullName && scraperData?.[index]?.basic_info) {
        const info = scraperData[index].basic_info;
        fullName = info.fullname || (info.first_name + " " + info.last_name);
    }

    // --- İSİM AYRIŞTIRMA ---
    let firstName = "";
    let lastName = "";
    if (fullName && typeof fullName === 'string') {
        let cleanName = fullName.split('(')[0].trim();
        const parts = cleanName.split(" ");
        if (parts.length > 1) {
            lastName = parts.pop();
            firstName = parts.join(" ");
        } else {
            firstName = fullName;
        }
    }

    // --- DOMAIN ve EMAIL ---
    let domain = "";
    const url = json.url || json.link || ""; 
    const scrapedEmail = json.scraped_email || ""; 

    try {
        if (url) {
            const safeUrl = url.startsWith('http') ? url : 'https://' + url;
            domain = new URL(safeUrl).hostname.replace(/^www\./, '');
        }
    } catch (e) {}

    if (!domain && scrapedEmail && scrapedEmail.includes('@')) {
        domain = scrapedEmail.split('@')[1]; 
    }

    // --- EMAIL PERMÜTASYONLARI ---
    let generatedEmails = [];
    if (domain && firstName && lastName) {
        const f = sanitize(firstName);
        const l = sanitize(lastName);
        const fi = f.charAt(0);

        generatedEmails.push(`${f}.${l}@${domain}`);
        generatedEmails.push(`${fi}${l}@${domain}`);
        generatedEmails.push(`${f}@${domain}`);
        generatedEmails.push(`${f}${l}@${domain}`);
        generatedEmails.push(`${fi}.${l}@${domain}`);
    }

    let allEmails = [];
    if (scrapedEmail) allEmails.push(scrapedEmail);
    generatedEmails.forEach(mail => {
        if (!allEmails.includes(mail)) allEmails.push(mail);
    });

    // --- KRİTİK KISIM: ESKİ VE YENİ VERİYİ BİRLEŞTİRME ---
    // ...json diyerek önceki node'dan gelen tüm verileri koruyoruz.
    // Sonra kendi yeni alanlarımızı ekliyoruz.
    return {
        json: {
            ...json, // <--- BU SATIR HAYATİ ÖNEM TAŞIR (Title, About vs. burada)
            first_name: firstName,
            last_name: lastName,
            domain: domain,     
            original_scraped_email: scrapedEmail,
            scraped_email: allEmails.join(", "), // Güncellenmiş mail listesi
            final_phone: json.scraped_phone // Telefon
        }
    };
});

// Workflow'un kalıcı hafızasını çağırıyoruz
const staticData = $getWorkflowStaticData('global');
const input = $input.first().json;

// --- MANTIK: SIFIRLA veya ARTIR ---

// Eğer veri en baştan (Set Fields1) geliyorsa, hafızayı SIFIRLA.
// (Set Fields1 node'unda 'currentStartIndex' veya 'number_of_search' gibi bir değişken olduğunu varsayıyoruz)
// Eğer input içinde "Set Fields1"den gelen özel bir sinyal varsa başa dön.
// NOT: Burası çok kritik. İlk tur olduğunu anlamak için Set Fields1'den gelen unique bir veriye bakıyoruz.
if (input.currentStartIndex !== undefined || input.startIndex === 1) {
    staticData.offset = 0;
} 
else {
    // Eğer veri Wait/Loop'tan geliyorsa, hafızadaki sayıyı ARTIR.
    // Eğer hafıza boşsa (hata durumu) 0'dan başlat.
    if (staticData.offset === undefined) {
        staticData.offset = 0;
    }
    // Her turda 10 ekle (Google'ın sayfa mantığı)
    staticData.offset += 10;
}

// --- URL OLUŞTURMA ---

// Sorgu metnini al (Kaybolmaması için en baştaki node'dan garantiye alıyoruz)
const queryText = input.q || $('Set Fields1').first().json.q;

// Linki oluştur
const googleUrl = `https://www.google.com/search?q=${encodeURIComponent(queryText)}&start=${staticData.offset}`;

return {
    json: {
        generated_url: googleUrl, // Apify'a gidecek link
        current_offset: staticData.offset, // Kontrol için (0, 10, 20...)
        page_number: (staticData.offset / 10) + 1 // Sayfa no (1, 2, 3...)
    }
};
